#include <bits/stdc++.h>
using namespace std;

unsigned int reverseBits(unsigned int n) {
    unsigned int rev = 0;

    // Process all 32 bits
    for(int i = 0; i < 32; i++) {
        // Left shift rev to make space for next bit
        rev <<= 1;

        // If current bit in n is 1, add it to rev
        if(n & 1) {
            rev |= 1;
        }

        // Right shift n to process next bit
        n >>= 1;
    }

    return rev;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        unsigned int n;
        cin >> n;
        cout << reverseBits(n) << endl;
    }

    return 0;
}

